ALGORITHM S/MIME Secure Email Process
INPUT: plaintext_email, sender_private_key, sender_certificate, recipient_public_key
OUTPUT: encrypted_signed_email

// ============================================
// PHASE 1: KEY AND CERTIFICATE GENERATION
// ============================================

BEGIN PROCEDURE GenerateKeyPair(key_size)
 BEGIN
 SELECT random prime p
 SELECT random prime q
 COMPUTE n = p * q // modulus
 COMPUTE phi = (p-1) * (q-1) // Euler's totient
 SELECT e where 1 < e < phi and gcd(e, phi) = 1
 COMPUTE d = e^(-1) mod phi // private exponent
 RETURN (public_key = {e, n}, private_key = {d, n})
 END

BEGIN PROCEDURE CreateCertificate(public_key, identity)
 BEGIN
 certificate_data = {identity, public_key, validity_period}
 signature = Sign(certificate_data, CA_private_key)
 RETURN X509Certificate(certificate_data, signature)
 END

// ============================================
// PHASE 2: MESSAGE DIGEST AND SIGNING
// ============================================

BEGIN PROCEDURE SignMessage(message, private_key)
 BEGIN
 digest = HashSHA256(message) // Generate message hash
 signature = EncryptRSA(digest, private_key)
 RETURN signature
 END

// ============================================
// PHASE 3: ENCRYPTION (HYBRID ENCRYPTION)
// ============================================

BEGIN PROCEDURE EncryptEmail(message, recipient_public_key)
 BEGIN
 // Generate random symmetric session key
 session_key = GenerateRandomAESKey(256)

 // Encrypt message with symmetric key (AES)
 encrypted_message = EncryptAES(message, session_key)

 // Encrypt session key with recipient's public key (RSA)
 encrypted_session_key = EncryptRSA(session_key, recipient_public_key)

 RETURN {encrypted_message, encrypted_session_key}
 END

// ============================================
// PHASE 4: S/MIME MESSAGE CONSTRUCTION
// ============================================

BEGIN PROCEDURE CreateSMIMEMessage(plaintext, sender_private_key, sender_cert, recipient_pub_key)
 BEGIN
 // Step 1: Create digital signature
 signature = SignMessage(plaintext, sender_private_key)
 signed_data = {plaintext, signature, sender_cert}

 // Step 2: Encrypt the signed data
 encrypted_content = EncryptEmail(signed_data, recipient_pub_key)

 // Step 3: Build S/MIME envelope
 smime_message = {
 content_type = "application/pkcs7-mime",
 smime_type = "enveloped-data",
 encrypted_content = encrypted_content,
 certificate = sender_cert
 }

 RETURN smime_message
 END

// ============================================
// PHASE 5: VERIFICATION AND DECRYPTION
// ============================================

BEGIN PROCEDURE DecryptAndVerify(smime_message, recipient_private_key, sender_cert)
 BEGIN
 // Step 1: Decrypt to get signed data
 session_key = DecryptRSA(smime_message.encrypted_session_key, recipient_private_key)
 signed_data = DecryptAES(smime_message.encrypted_content, session_key)

 // Step 2: Verify digital signature
 original_digest = HashSHA256(signed_data.plaintext)
 decrypted_signature = DecryptRSA(signed_data.signature, sender_cert.public_key)

 IF original_digest = decrypted_signature THEN
 RETURN {verified = TRUE, message = signed_data.plaintext}
 ELSE
 RETURN {verified = FALSE, message = NULL}
 END IF
 END

// ============================================
// MAIN EXECUTION EXAMPLE
// ============================================

BEGIN
 // Generate key pairs
 (sender_pub, sender_priv) = GenerateKeyPair(2048)
 (recipient_pub, recipient_priv) = GenerateKeyPair(2048)

 // Create certificates
 sender_cert = CreateCertificate(sender_pub, "sender@example.com")

 // Create and send secure email
 email_content = "Confidential message"
 smime = CreateSMIMEMessage(email_content, sender_priv, sender_cert, recipient_pub)

 // Receive and verify
 result = DecryptAndVerify(smime, recipient_priv, sender_cert)
 OUTPUT result
END

/*
 * S/MIME Digital Signature Implementation in C
 * Demonstrates RSA key generation, SHA-256 hashing, and signing
 * For educational purposes - uses OpenSSL library
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <openssl/rsa.h>
#include <openssl/pem.h>
#include <openssl/err.h>
#include <openssl/sha.h>
#include <openssl/objects.h>

#define KEY_SIZE 2048
#define MAX_BUFFER 4096

/* Structure to hold S/MIME keys */
typedef struct {
 RSA *public_key;
 RSA *private_key;
} SMIMEKeyPair;

/* Function to handle OpenSSL errors */
void handle_openssl_errors(void) {
 ERR_print_errors_fp(stderr);
 exit(1);
}

/*
 * Generate RSA Key Pair for S/MIME
 * Uses 2048-bit key size (recommended minimum)
 */
SMIMEKeyPair* generate_keypair(int key_size) {
 SMIMEKeyPair *keys = malloc(sizeof(SMIMEKeyPair));

 if (!keys) {
 fprintf(stderr, "Memory allocation failed\n");
 return NULL;
 }

 // Generate RSA key pair
 keys->private_key = RSA_generate_key(key_size, 65537, NULL, NULL);

 if (!keys->private_key) {
 fprintf(stderr, "Failed to generate private key\n");
 handle_openssl_errors();
 }

 // Extract public key from private key
 keys->public_key = RSAPublicKey_dup(keys->private_key);

 if (!keys->public_key) {
 fprintf(stderr, "Failed to extract public key\n");
 handle_openssl_errors();
 }

 printf("[S/MIME] RSA %d-bit key pair generated successfully\n", key_size);
 return keys;
}

/*
 * Compute SHA-256 Hash of Message
 * Used in digital signature process
 */
unsigned char* compute_sha256_hash(const char *message, size_t msg_len, 
 unsigned char *hash_out) {
 SHA256((const unsigned char*)message, msg_len, hash_out);
 return hash_out;
}

/*
 * Create Digital Signature
 * Process: Hash(message) -> Encrypt with private key
 * This is the core of S/MIME authentication
 */
unsigned char* create_signature(const char *message, size_t msg_len,
 RSA *private_key, unsigned char *sig_out) {
 unsigned char hash[SHA256_DIGEST_LENGTH];
 unsigned char *encrypted_hash = NULL;
 int sig_len;

 // Step 1: Compute SHA-256 hash of message
 compute_sha256_hash(message, msg_len, hash);
 printf("[S/MIME] Message hash computed: ");
 for (int i = 0; i < SHA256_DIGEST_LENGTH; i++)
 printf("%02x", hash[i]);
 printf("\n");

 // Step 2: Allocate buffer for encrypted hash
 encrypted_hash = malloc(RSA_size(private_key));
 if (!encrypted_hash) {
 fprintf(stderr, "Memory allocation failed\n");
 return NULL;
 }

 // Step 3: Encrypt hash with private key (digital signature)
 sig_len = RSA_private_encrypt(
 SHA256_DIGEST_LENGTH,
 hash,
 encrypted_hash,
 private_key,
 RSA_PKCS1_PADDING
 );

 if (sig_len <= 0) {
 fprintf(stderr, "Signature creation failed\n");
 handle_openssl_errors();
 }

 // Copy signature to output
 memcpy(sig_out, encrypted_hash, sig_len);
 free(encrypted_hash);

 printf("[S/MIME] Digital signature created (%d bytes)\n", sig_len);
 return sig_out;
}

/*
 * Verify Digital Signature
 * Process: Decrypt signature with public key -> Compare with hash
 */
int verify_signature(const char *message, size_t msg_len,
 unsigned char *signature, int sig_len,
 RSA *public_key) {
 unsigned char hash[SHA256_DIGEST_LENGTH];
 unsigned char decrypted_hash[SHA256_DIGEST_LENGTH];
 int decrypted_len;

 // Step 1: Compute hash of received message
 compute_sha256_hash(message, msg_len, hash);

 // Step 2: Decrypt signature using public key
 decrypted_len = RSA_public_decrypt(
 sig_len,
 signature,
 decrypted_hash,
 public_key,
 RSA_PKCS1_PADDING
 );

 if (decrypted_len <= 0) {
 fprintf(stderr, "Signature verification failed\n");
 return 0;
 }

 // Step 3: Compare decrypted hash with computed hash
 if (memcmp(hash, decrypted_hash, SHA256_DIGEST_LENGTH) == 0) {
 printf("[S/MIME] ✓ Signature VERIFIED - Message is authentic\n");
 return 1;
 } else {
 printf("[S/MIME] ✗ Signature INVALID - Message may be tampered\n");
 return 0;
 }
}

/*
 * S/MIME Message Structure (Simplified)
 * Demonstrates the data that would be in an S/MIME email
 */
typedef struct {
 char *content_type; // "application/pkcs7-mime"
 char *smime_type; // "signed-data" or "enveloped-data"
 char *sender_email;
 char *recipient_email;
 unsigned char *message_content;
 size_t content_length;
 unsigned char *signature;
 size_t signature_length;
} SMIMEMessage;

/*
 * Create a signed S/MIME message
 */
SMIMEMessage* create_signed_message(const char *email_body, 
 const char *sender, const char *recipient,
 SMIMEKeyPair *keys) {
 SMIMEMessage *msg = malloc(sizeof(SMIMEMessage));

 if (!msg) return NULL;

 // Set message metadata
 msg->content_type = "application/pkcs7-mime";
 msg->smime_type = "signed-data";
 msg->sender_email = strdup(sender);
 msg->recipient_email = strdup(recipient);
 msg->message_content = (unsigned char*)strdup(email_body);
 msg->content_length = strlen(email_body);

 // Create digital signature
 msg->signature = malloc(RSA_size(keys->private_key));
 if (!msg->signature) {
 free(msg);
 return NULL;
 }

 msg->signature_length = (size_t)create_signature(
 email_body, 
 strlen(email_body),
 keys->private_key,
 msg->signature
 );

 printf("[S/MIME] Signed message created\n");
 return msg;
}

/*
 * Verify received S/MIME message
 */
int verify_received_message(SMIMEMessage *msg, RSA *sender_public_key) {
 return verify_signature(
 (const char*)msg->message_content,
 msg->content_length,
 msg->signature,
 msg->signature_length,
 sender_public_key
 );
}

/* Cleanup function */
void cleanup_keys(SMIMEKeyPair *keys) {
 if (keys) {
 if (keys->public_key) RSA_free(keys->public_key);
 if (keys->private_key) RSA_free(keys->private_key);
 free(keys);
 }
}

/* Main demonstration */
int main() {
 printf("========================================\n");
 printf("S/MIME Digital Signature Demo in C\n");
 printf("========================================\n\n");

 // Initialize OpenSSL
 OpenSSL_add_all_algorithms();
 ERR_load_crypto_strings();

 // Generate key pairs
 printf("[1] Generating RSA key pair...\n");
 SMIMEKeyPair *sender_keys = generate_keypair(KEY_SIZE);
 SMIMEKeyPair *recipient_keys = generate_keypair(KEY_SIZE);

 // Create email message
 const char *email_body = "From: alice@example.com\n"
 "To: bob@example.com\n"
 "Subject: Confidential Document\n\n"
 "This is a secure S/MIME message with digital signature.";

 printf("\n[2] Original Email:\n%s\n", email_body);

 // Create signed S/MIME message
 printf("\n[3] Creating signed S/MIME message...\n");
 SMIMEMessage *signed_msg = create_signed_message(
 email_body,
 "alice@example.com",
 "bob@example.com",
 sender_keys
 );

 // Verify the signature
 printf("\n[4] Verifying signature...\n");
 int is_valid = verify_received_message(signed_msg, sender_keys->public_key);

 // Simulate tampering
 printf("\n[5] Simulating message tampering...\n");
 signed_msg->message_content[10] = 'X'; // Tamper with message

 printf("\n[6] Verifying tampered message...\n");
 is_valid = verify_received_message(signed_msg, sender_keys->public_key);

 // Cleanup
 printf("\n[7] Cleaning up resources...\n");
 cleanup_keys(sender_keys);
 cleanup_keys(recipient_keys);
 free(signed_msg);

 printf("\n========================================\n");
 printf("Demo Complete!\n");
 printf("========================================\n");

 return 0;
}
